findings.codeql_raw_query:
/**
 * @name OpenApiInterceptor - parameter to handleResourceRequest to getResource
 * @description Trace the path parameter through serveSwaggerUi -> handleResourceRequest -> getResource
 * @kind path-problem
 * @problem.severity error
 * @id java/openapi-param-to-resource
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-706
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module OpenApiResourceConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Parameters of handleResourceRequest (which receives the path from serveSwaggerUi)
    exists(Parameter p |
      p.getCallable().getDeclaringType().hasQualifiedName("ca.uhn.fhir.rest.openapi", "OpenApiInterceptor") and
      p.getCallable().hasName("handleResourceRequest") and
      source.asParameter() = p
    )
    or
    // Parameters of serveSwaggerUi
    exists(Parameter p |
      p.getCallable().getDeclaringType().hasQualifiedName("ca.uhn.fhir.rest.openapi", "OpenApiInterceptor") and
      p.getCallable().hasName("serveSwaggerUi") and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // ClassLoader.getResource / getResourceAsStream 
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("ca.uhn.fhir.rest.openapi", "OpenApiInterceptor") and
      (mc.getMethod().hasName("getResource") or mc.getMethod().hasName("getResourceAsStream")) and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // ClasspathUtil calls
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("ca.uhn.fhir.rest.openapi", "OpenApiInterceptor") and
      mc.getMethod().getDeclaringType().hasQualifiedName("ca.uhn.fhir.util", "ClasspathUtil") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module OpenApiResourceFlow = TaintTracking::Global<OpenApiResourceConfig>;
import OpenApiResourceFlow::PathGraph

from OpenApiResourceFlow::PathNode source, OpenApiResourceFlow::PathNode sink
where OpenApiResourceFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "HTTP path parameter flows to resource loading in OpenApiInterceptor from $@.", source.getNode(), "parameter"
